/// Returns leaf id in [0, LEAF_COUNT) for a quantized i16 query vector.
pub fn predict(q: *const [norm.PADDED_DIMS]i16) u16 {
    var node: i32 = 0;
    while (true) {
        const n = NODES[@intCast(node)];
        if (n.left < 0) {
            return @intCast(-1 - n.left);
        }
        const go_left = q[n.feature] <= n.threshold;
        node = if (go_left) n.left else n.right;
    }
}
